//vip.opstream15.com/20230327/36380_aca74bd6/index.m3u8"},{"name":"17","slug":"17","filename":"Lộ Trình Nghề Nghiệp Đến Đỉnh Cao - Tập 17","link_embed":"https://vip.opstream15.com/share/5e487b1018c4652d45114ef8477f8f8c","link_m3u8":"https://vip.opstream15.com/20230327/36381_c8374899/index.m3u8"},{"name":"18","slug":"18","filename":"Lộ Trình Nghề Nghiệp Đến Đỉnh Cao - Tập 18","link_embed":"https://vip.opstream15.com/share/1fe6eda65dcd46c3a5ad1789c3bf08f5","link_m3u8":"https://vip.opstream15.com/20230327/36382_8a4d1b76/index.m3u8"}]}],"time":"10 phút/tập","description":"<p>Một bộ phim hài nhẹ nhàng về đô thị lấy bối cảnh là giáo dục nghề nghiệp, kể về câu chuyện của Yang Xiaoqi, nữ anh hùng khao khát trở thành bậc thầy về máy xúc, và Bai He, nữ anh hùng khao khát trở thành người dẫn đầu ngành làm đẹp và làm tóc., một câu chuyện đầy cảm hứng về việc thành lập một nhóm chuyên nghiệp liên kỹ thuật với các sinh viên từ lớp đầu bếp và lớp sửa chữa ô tô để tham gia hỗ trợ khôi phục nông thôn của trường. Bộ phim phù hợp với định hướng chủ đạo và kế hoạch giáo dục phát triển mạnh mẽ giáo dục nghề nghiệp của đất nước, thông qua các nhân vật trẻ trung, câu chuyện hài hước và cốt truyện sinh động, cảm động, bộ phim đã mở ra một bức tranh đầy màu sắc về phổ cập và quảng bá giáo dục nghề nghiệp.</p>","tmdb":{"type":null,"id":"","season":null,"vote_average":0,"vote_count":0},"modified":"2023-03-27T13:39:47.000Z","_image_preserved":true},{"id":"64213ce5162420646b020a2f","_id":"64213ce5162420646b020a2f","title":"Trận Chiến Thế Giới Ngầm","origin_name":"Kill the Drug Lords","slug":"tran-chien-the-gioi-ngam","year":2023,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a2249e0fc277084dfd2e5","name":"Hình Sự","slug":"hinh-su"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"tran-chien-the-gioi-ngam-2023","link_embed":"https://vip.opstream14.com/share/4bd51b84dd6a0f7ec89401fedf627fec","link_m3u8":"https://vip.opstream14.com/20230327/34186_63c547ee/index.m3u8"}]}],"time":"93 Phút","description":"Bộ phim kể về câu chuyện của các sĩ quan cảnh sát công an như Cục trưởng Cục Cảnh Sát Lãnh Kiệt và cảnh sát chìm Trương Chính Dương cùng chiến đấu chống lại các nhóm tội phạm thế giới ngầm và sau cùng anh dũng hy sinh. Đồng thời khắc hoạ tình đồng chí, tình gia đình, tình yêu thương, làm thăng hoa hình ảnh người chiến sĩ công an nhân dân cũng bằng xương bằng thịt nhưng có thể đứng dậy trong gian nguy, bên cạnh đó truyền tải đến xã hội sự đúng đắn của đề cao công lý và thượng tôn pháp luật.\\nBộ phim thể hiện mặt thiết yếu và kiên quyết của Đảng và Nhà nước trong công cuộc đấu tranh chống tội phạm bằng cách phơi bày tội ác của bọn côn đồ và thế lực xấu xa gây nguy hiểm cho an ninh xã hội và người dân, thể hiện quan niệm đặt nhân dân lên hàng đầu và diễn giải chân lý “Chính nghĩa luôn chiến thắng cái ác”, tiếp nối truyền thống vẻ vang của Đảng là luôn nghĩ đến sự an toàn và hạnh phúc của người dân.\\nCuối cùng, bằng cách đưa ra các kết cục khác nhau của nhân vật chính diện và phản diện, bộ phim truyền tải những giá trị đúng đắn, giá trị đạo đức và nhân sinh quan đến thế hệ trẻ, trên đời này không có con đường tắt dẫn đến thành công.","tmdb":{"type":"movie","id":"1094486","season":null,"vote_average":9,"vote_count":1},"modified":"2023-03-27T14:51:43.000Z","_image_preserved":true},{"id":"64213d2d162420646b020ac0","_id":"64213d2d162420646b020ac0","title":"Bữa Tiệc Đẫm Máu","origin_name":"Kill Her Goats","slug":"bua-tiec-dam-mau","year":2023,"type":"single","genre":[{"id":"620a22ace0fc277084dfd531","name":"Kinh Dị","slug":"kinh-di"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","sl